import pandas as pd

# Get data from storage
cases_key = 'var_functions.query_db:12'
casehistory_key = 'var_functions.query_db:8'

cases_data = locals()[cases_key]
casehistory_file = locals()[casehistory_key]

# Process cases
cases_df = pd.DataFrame(cases_data)

# Read casehistory
with open(casehistory_file, 'r') as f:
    casehistory_data = json.load(f)

# Filter for Owner Assignment
owner_assignments = []
for rec in casehistory_data:
    if rec.get('field__c') == 'Owner Assignment':
        owner_assignments.append(rec)

# Count assignments per case
case_counts = {}
for assignment in owner_assignments:
    case_id = assignment['caseid__c']
    case_counts[case_id] = case_counts.get(case_id, 0) + 1

# Find cases in our date range
date_range_case_ids = set(cases_df['id'].tolist())

# Get non-transferred cases (exactly 1 assignment) that are in our date range
non_transferred_case_ids = []
for case_id, count in case_counts.items():
    if count == 1 and case_id in date_range_case_ids:
        non_transferred_case_ids.append(case_id)

# Get the ownerid for each non-transferred case in our range
non_transferred_data = []
for assignment in owner_assignments:
    case_id = assignment['caseid__c']
    if case_id in non_transferred_case_ids:
        non_transferred_data.append({
            'caseid': case_id,
            'ownerid': assignment['newvalue__c'],
            'assignment_date': assignment['createddate']
        })

# Group by owner and count their cases
owner_case_counts = {}
case_owner_map = {}
for item in non_transferred_data:
    ownerid = item['ownerid']
    caseid = item['caseid']
    owner_case_counts[ownerid] = owner_case_counts.get(ownerid, 0) + 1
    case_owner_map[caseid] = ownerid

# Filter agents who handled more than one case
agents_multiple_cases = {ownerid: count for ownerid, count in owner_case_counts.items() if count > 1}

# Calculate handle time for these agents
handle_times = {}
case_data_lookup = {row['id']: row for _, row in cases_df.iterrows()}

for ownerid in agents_multiple_cases:
    handle_times[ownerid] = []

for caseid, ownerid in case_owner_map.items():
    if ownerid in agents_multiple_cases and caseid in case_data_lookup:
        case_data = case_data_lookup[caseid]
        try:
            created = pd.to_datetime(case_data['createddate'])
            closed = pd.to_datetime(case_data['closeddate'])
            handle_time = (closed - created).total_seconds() / 3600  # in hours
            handle_times[ownerid].append(handle_time)
        except:
            pass

# Calculate average handle times
agent_avg_handle_time = {}
for ownerid, times in handle_times.items():
    if times:
        avg_time = sum(times) / len(times)
        agent_avg_handle_time[ownerid] = avg_time

# Find agent with lowest average handle time
if agent_avg_handle_time:
    lowest_agent = min(agent_avg_handle_time, key=agent_avg_handle_time.get)
    result = lowest_agent
else:
    result = "No agents found"

print("__RESULT__:")
print(json.dumps(result))"}

